var e=[{id:`L2_1`,type:`dialog`,speaker:`DASH_HORIZON_NULL_NULL`,text:{KOREA:`사진, 사진, 사진......! 어디 있니, 사진아......!`,JPN:`写真、写真、写真……！　写真はどこ……？`,ENG:`Photo, photo, photo... Where is the photo?`,TWN:`照片，照片，照片……！在哪呢，照片……！`},stage:{bg:`CORRIDOR_04`,slots:{L:null,C:{char_id:`DASH_HORIZON_NULL_NULL`,face:`UNIT_SERIOUS`},R:null}}},{id:`L4_1`,type:`dialog`,speaker:`DASH_HORIZON_NULL_NULL`,text:{KOREA:`으와앙!?`,JPN:`うわっ！？`,ENG:`Eeeek?!`,TWN:`哦哇啊！？`},stage:{bg:`CORRIDOR_04`,slots:{L:null,C:{char_id:`DASH_HORIZON_NULL_NULL`,face:`UNIT_SURPRISE`},R:null}}},{id:`L6_1`,type:`dialog`,speaker:`RITA_HORIZON_NULL_NULL`,text:{KOREA:`꼬맹이, 거기 처박혀서 뭐 해!`,JPN:`ガキ、そこで何をしている！`,ENG:`What are you doing in there, kid!`,TWN:`小鬼，你在那裡幹什麼！`},stage:{bg:`CORRIDOR_04`,slots:{L:null,C:{char_id:`RITA_HORIZON_NULL_NULL`,face:`UNIT_SERIOUS`},R:null}}},{id:`L7_1`,type:`dialog`,speaker:`DASH_HORIZON_NULL_NULL`,text:{KOREA:`죄, 죄송해요!`,JPN:`ご、ごめんなさい！`,ENG:`S-sorry!`,TWN:`對、對不起！`},stage:{bg:`CORRIDOR_04`,slots:{L:null,C:{char_id:`DASH_HORIZON_NULL_NULL`,face:`UNIT_SURPRISE`},R:null}}},{id:`L9_1`,type:`dialog`,speaker:`DASH_HORIZON_NULL_NULL`,text:{KOREA:`앗?! 사진이다!`,JPN:`あっ！　あった！`,ENG:`Oh! There it is!`,TWN:`啊？！是照片！`},stage:{bg:`CORRIDOR_04`,slots:{L:null,C:{char_id:`DASH_HORIZON_NULL_NULL`,face:`UNIT_PRIDE`},R:null}}},{id:`L10_1`,type:`dialog`,speaker:`DASH_HORIZON_NULL_NULL`,text:{KOREA:`리타 언니! 사진 찾았어요!`,JPN:`リタお姉ちゃん！　写真を見つけました！`,ENG:`Rita! I found the photo!`,TWN:`麗塔姐姐！我找到照片了！`},stage:{bg:`CORRIDOR_04`,slots:{L:null,C:{char_id:`DASH_HORIZON_NULL_NULL`,face:`UNIT_IDLE`},R:null}}},{id:`L12_1`,type:`dialog`,speaker:`RITA_HORIZON_NULL_NULL`,text:{KOREA:`자랑할 시간 없어! 당장 찢어 버려!`,JPN:`いちいち報告しなくていいから！　今すぐ破れ！`,ENG:`We don't have time for show and tell! Just destroy it now!`,TWN:`別炫耀了！快撕了它！`},stage:{bg:`CORRIDOR_04`,slots:{L:null,C:{char_id:`RITA_HORIZON_NULL_NULL`,face:`UNIT_SERIOUS`},R:null}}},{id:`L14_1`,type:`dialog`,speaker:`SPIRA_CORRUPT_NULL_SHADE`,text:{KOREA:`아......`,JPN:`あ……`,ENG:`Ah...`,TWN:`啊……`},stage:{bg:`CORRIDOR_04`,slots:{L:null,C:{char_id:`SPIRA_CORRUPT_NULL_SHADE`,face:`UNIT_SURPRISE`},R:null}}},{id:`L15_1`,type:`dialog`,speaker:`SPIRA_CORRUPT_NULL_SHADE`,text:{KOREA:`추워...... 언, 니......`,JPN:`寒いよ……お姉ちゃん……`,ENG:`It's cold... Sis...`,TWN:`好冷……姐、姐姐……`},stage:{bg:`CORRIDOR_04`,slots:{L:null,C:{char_id:`SPIRA_CORRUPT_NULL_SHADE`,face:`UNIT_DESPAIR`},R:null}}},{id:`L16_1`,type:`dialog`,speaker:`SPIRA_CORRUPT_NULL_SHADE`,text:{KOREA:`이제, 그만...... 집으로......`,JPN:`もう……家に……`,ENG:`Let's... go home...`,TWN:`現在，要……回家……`},stage:{bg:`CORRIDOR_04`,slots:{L:null,C:{char_id:`SPIRA_CORRUPT_NULL_SHADE`,face:`UNIT_IDLE`},R:null}}},{id:`L19_1`,type:`dialog`,speaker:`HORIZON_HORIZON_NULL_DRONE`,text:{KOREA:`침식파 반응 소멸. 유사 데몬 타입 침식체의 격퇴에 성공했습니다.`,JPN:`侵食波反応消滅。疑似デーモンタイプの侵食体の撃退に成功しました。`,ENG:`Corruption Ray response no longer detected. The quasi demon-type C.O. has been defeated.`,TWN:`侵蝕波反應消失。成功擊退類似惡魔型侵蝕體。`},stage:{bg:`CORRIDOR_04`,slots:{L:null,C:{char_id:`HORIZON_HORIZON_NULL_DRONE`,face:`UNIT_IDLE`},R:null}}},{id:`L22_1`,type:`dialog`,speaker:`DASH_HORIZON_NULL_NULL`,text:{KOREA:`정말요?! 저희가 이겼어요?!`,JPN:`本当！？　私たちの勝ちですか？`,ENG:`Really?! Did we really win?!`,TWN:`真的嗎？！我們贏了？！`},stage:{bg:`CORRIDOR_04`,slots:{L:{char_id:`DASH_HORIZON_NULL_NULL`,face:`UNIT_PRIDE`},C:null,R:{char_id:`RITA_HORIZON_NULL_NULL`,face:`UNIT_DESPAIR`}}}},{id:`L23_1`,type:`dialog`,speaker:`RITA_HORIZON_NULL_NULL`,text:{KOREA:`쳇...... 시답잖은 일로 힘을 너무 낭비했어.`,JPN:`ちっ……くだらんことで力を無駄に使いすぎた。`,ENG:`Hmpf... I wasted too much energy on that stupid thing.`,TWN:`切……為一點小事浪費太多力氣了。`},stage:{bg:`CORRIDOR_04`,slots:{L:{char_id:`DASH_HORIZON_NULL_NULL`,face:`UNIT_PRIDE`},C:null,R:{char_id:`RITA_HORIZON_NULL_NULL`,face:`UNIT_IDLE`}}}},{id:`L24_1`,type:`dialog`,speaker:`DASH_HORIZON_NULL_NULL`,text:{KOREA:`리타 언니! 고생 많았어요! 언니 덕분에 `,JPN:`リタお姉ちゃん！　お疲れ様でした！　おかげで……`,ENG:`Rita! Great work! Thanks to you— `,TWN:`麗塔姐姐！辛苦了！多虧了姐姐呢！`},stage:{bg:`CORRIDOR_04`,slots:{L:{char_id:`DASH_HORIZON_NULL_NULL`,face:`UNIT_PRIDE`},C:null,R:{char_id:`RITA_HORIZON_NULL_NULL`,face:`UNIT_IDLE`}}}},{id:`L25_1`,type:`dialog`,speaker:`DASH_HORIZON_NULL_NULL`,text:{KOREA:`으브븝!`,JPN:`うううっ！`,ENG:`Mmph!`,TWN:`呃啊！`},stage:{bg:`CORRIDOR_04`,slots:{L:{char_id:`DASH_HORIZON_NULL_NULL`,face:`UNIT_SURPRISE`},C:null,R:{char_id:`RITA_HORIZON_NULL_NULL`,face:`UNIT_IDLE`}}}},{id:`L27_1`,type:`dialog`,speaker:`RITA_HORIZON_NULL_NULL`,text:{KOREA:`너, 팔에 그 상처는 뭐야? 언제 생겼어?`,JPN:`おい、お前その腕の傷はなんだ？　いつやった？`,ENG:`What's that scratch on your arm? When did you get hurt?`,TWN:`你，手臂上的傷是怎麼回事？什麼時候受傷的？`},stage:{bg:`CORRIDOR_04`,slots:{L:null,C:{char_id:`RITA_HORIZON_NULL_NULL`,face:`UNIT_SERIOUS`},R:null}}}];export{e as default};